import React, { FC, RefObject } from "react"
import { FlatList, RefreshControl } from "react-native"
import { CardVehicleTags, Text, Image, Box, Skeleton, PropsIconsNameCore } from "@semparar/design-system-app"
import BasicScreen from "../../atomic/templates/BasicScreen"
import ApiError from '../../atomic/organisms/ApiError';
import FiltersBottomSheet from '../../atomic/organisms/FiltersBottomSheet';
import { MyOrdersItemPropsView, STATUS_COLORS } from "./models";
import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";

const MyOrdersCashbackView: FC<MyOrdersItemPropsView> = ({
    handleGoBack,
    myOrders,
    emptyImage,
    formatDate,
    isLoading,
    isError,
    modalizeRefFilters,
    handleOpenFilters,
    handleDetailsOrders,
    handleRefresh,
    filterGroups,
    isRefreshing,
    skeletonCount,
    screenWidth
}) => {

    return (
        <BasicScreen
            title="Meus pedidos"
            errorButtonOnPress={() => { }}
            hasScroll
            leftIconOnPress={handleGoBack}
            rightIcon="icon-filter-settings"
            rightIconOnPress={handleOpenFilters}
            hasRightIcon={!!myOrders.length}
            scrollViewProps={{
                refreshControl: (
                    <RefreshControl
                        onRefresh={handleRefresh}
                        refreshing={isRefreshing}
                        tintColor={"BRAND_BASE_01"}
                    />
                ),
            }}
        >

            {isLoading && (
                <Box width={screenWidth} mt="nano">
                    <FlatList
                        testID="loading-list-cashback"
                        data={Array.from({ length: skeletonCount })}
                        keyExtractor={(_, index) => index.toString()}
                        scrollEnabled={false}
                        renderItem={() => (
                            <Skeleton
                                testID="loading-orders-cashback"
                                width={screenWidth - 64}
                                height={150}
                                type="light"
                                mt="nano"
                                mb="nano"
                                mr="medium"
                                ml="medium"
                                borderRadiusTopLeft="half"
                            />
                        )}

                    />
                </Box>
            )}


            {isError && (
                <ApiError
                    testID="orders-cashback-error"
                    title="Algo deu errado!"
                    subTitle="Por favor, tente mais tarde"
                    isLoading={isLoading}
                    hasBackToHome={false}
                    onPress={handleGoBack}
                />
            )}


            {!isLoading && !isError && (<FlatList
                data={myOrders}
                renderItem={({ item }) => (
                    <Box ml="middle" mr="middle" mt="smaller">
                        <CardVehicleTags
                            vehicleName={item.description}
                            icon={item.icon as PropsIconsNameCore}
                            title="Valor em pontos"
                            titleDescription={String(Math.abs(item.amount))}
                            date="Data do resgate"
                            dateNumber={formatDate(item.date)}
                            statusTitle="Status do pedido"
                            status={item.status}
                            ghostButtonText="Exibir detalhes"
                            onGhostButtonPress={handleDetailsOrders}
                            type="extended"
                            typeTag={STATUS_COLORS[item.status] ?? 'alert'}
                            version="2.0"
                        />
                    </Box>
                )}
                ListEmptyComponent={() => (
                    <Box align="center" pd="innerLarger" justify="center" mt="larger">
                        <Image
                            resizeMode="contain"
                            source={{ uri: emptyImage }}
                            width={80}
                            height={80}
                        />

                        <Text type="paragraphXXXL" mt="nano">
                            Nenhum pedido feito
                        </Text>
                        <Text type="paragraphLG" align="center" mt="nano">
                            Quando você usar seus pontos em pedidos, eles aparecerão aqui.
                        </Text>
                    </Box>
                )}
            />)}
            {filterGroups.length > 0 && (
                <FiltersBottomSheet
                    modalizeRef={modalizeRefFilters as RefObject<PropsModalizeRef>}
                    filterGroups={filterGroups}
                    onApplyFilters={() => { }}
                    initialFilters={{}}
                />
            )}

        </BasicScreen>
    )
}


export default MyOrdersCashbackView;

import { Box, Image } from '@semparar/design-system-app';
import { Text } from '@semparar/design-system-app/fintech';
import React from 'react';
import { Animated } from 'react-native';
import arrow from '../../../assets/images/arrow.png';
import { AnimationArrowsViewProps } from './Models';
import { Container } from './styles';

const AnimationArrowsView = ({
  arrow1Move,
  arrow1Fade,
  arrow2Move,
  arrow2Fade,
  arrow3Move,
  arrow3Fade,
}: AnimationArrowsViewProps) => {
  return (
    <Container testID="AnimationArrowsView">
      <Box
        justify="center"
        align="center"
        width="100%"
        overflow="hidden"
        height={175}
      >
        <Box direction justify="center">
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: -35 }, { translateY: arrow1Move }],
                opacity: arrow1Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateY: arrow2Move }],
                opacity: arrow2Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: 30 }, { translateY: arrow3Move }],
                opacity: arrow3Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
        </Box>
      </Box>
      <Text align="center" mt="middle" type="subtitleLarger">
        Estamos carregando suas informações...
      </Text>
    </Container>
  );
};

export default AnimationArrowsView;

