import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";
import { TypesTagLabel } from "@semparar/design-system-app/src/atomic/molecules/TagLabel/Models";
import { PointsTransaction } from "../../../services/models";

export const STATUS_COLORS: Record<string, TypesTagLabel> = {
    Pendente: 'highlight',
    Confirmado: 'highlight',
    Enviado: 'success',
    Finalizado: 'success',
    Estornado: 'error',
    Cancelado: 'alert'
};

export interface MyOrdersItem {
    id: string
    date: string
    description: string
    type: string
    amount: string
    icon: string
    status: string
    origination: string
}
export interface MyOrdersItemPropsView {
    myOrders: PointsTransaction[]
    emptyImage: string
    isLoading: boolean
    isError: boolean
    modalizeRefFilters: React.RefObject<PropsModalizeRef | null>
    filterGroups: {
        label: string;
        options: {
            label: string;
            value: number;
        }[];
    }[];
    isRefreshing: boolean;
    skeletonCount: number;
    screenWidth: number;
    formatDate: (iso?: string) => string;
    handleGoBack: () => void;
    handleOpenFilters: () => void;
    handleDetailsOrders: () => void;
    handleRefresh: () => void;

}

import { Button, Box } from '@semparar/design-system-app';
import { Text } from '@semparar/design-system-app/fintech';
import React, { FC } from 'react';
import { Image } from 'react-native';

import ErrorApi from '../../../assets/images/errorApi.png';
import { ApiErrorViewProps } from './Models';
import { Container, Content } from './styles';
import { Icon } from '@semparar/design-system-app';

const ApiErrorView: FC<ApiErrorViewProps> = ({
  onPress,
  title,
  subTitle,
  hasBackToHome,
  isLoading,
  handleNavigateToHome,
  testID,
}) => {
  return (
    <Container testID={testID}>
      <Content>
        {hasBackToHome ? (
          <Box width={100} align="center">
            <Image
              source={ErrorApi}
              style={{
                width: 188,
                height: 188,
              }}
            />
          </Box>
          ) : (
            <Box
              bgColor="DENY_COLOR_03"
              borderColor="DENY_COLOR_01"
              borderRadiusBottomLeft="medium"
              pd="innerMedium"
              borderRadiusBottomRight="medium"
              borderRadiusTopRight="medium"
              borderRadiusTopLeft="medium"
              borderBottomWidth="small"
              borderTopWidth="small"
              borderLeftWidth="small"
              borderRightWidth="small"
            >
              <Icon name="icon-circle-alert" color="DENY_COLOR_01" size="sm" />
            </Box>
          )}

        <Text mt="smaller" type="subtitleXXXXL" align="center">
          {title}
        </Text>

        {!!subTitle && (
          <Text
            align="center"
            mt="xxxxs"
            type="paragraphXXL"
            color="INTENSE_COLOR_03"
          >
            {subTitle}
          </Text>
        )}
      </Content>
      <Button
        testID="apiError_retry-button"
        isLoading={isLoading}
        text={hasBackToHome ? "Tentar novamente" : "Voltar"}
        mb="xs"
        onPress={onPress}
      />
      {
        hasBackToHome && (
          <Button
            mb="xs"
            type="ghostSmall"
            onPress={handleNavigateToHome}
            text="Voltar para a home"
          />
        )
      }
    </Container >
  );
};

export default ApiErrorView;

